 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getVolumes } from '@kubevirt-utils/resources/vm';
 8	import {
 9	  Alert,
10	  AlertVariant,
11	  Stack,
12	  StackItem,
13	  Text,
14	  TextVariants,
15	  Title,
16	} from '@patternfly/react-core';
17	import { Table, Tbody, Td, Tr } from '@patternfly/react-table';
18	
19	import { getVolumeFromPVC } from '../utils';
20	
21	type VirtualMachineMigrationReviewTabProps = {
22	  defaultStorageClassName: string;
23	  destinationStorageClass: string;
24	  migrationError: Error;
25	  pvcs: IoK8sApiCoreV1PersistentVolumeClaim[];
26	  vm: V1VirtualMachine;
27	};
28	
29	const VirtualMachineMigrationReviewTab: FC<VirtualMachineMigrationReviewTabProps> = ({
30	  defaultStorageClassName,
31	  destinationStorageClass,
32	  migrationError,
33	  pvcs,
34	  vm,
35	}) => {
36	  const { t } = useKubevirtTranslation();
37	
38	  const volumes = getVolumes(vm);
39	
40	  const volumesToMigrate = getVolumeFromPVC(volumes, pvcs);
41	
42	  return (
43	    <Stack hasGutter>
44	      <StackItem>
45	        <Title headingLevel="h2">{t('Review')}</Title>
46	        <Text component={TextVariants.p}>
47	          <Trans t={t}>
48	            Verify the details and click <strong>Migrate VirtualMachine storage</strong> to start
49	            the migration
50	          </Trans>
51	        </Text>
52	      </StackItem>
53	      <StackItem>
54	        <Table aria-label={t('Review')} borders={false} variant="compact">
55	          <Tbody>
56	            <Tr>
57	              <Td width={30}>
58	                <strong>{t('Migration type')}</strong>
59	              </Td>
60	              <Td>{t('VirtualMachine storage')}</Td>
61	            </Tr>
62	            <Tr>
63	              <Td width={30}>
64	                <strong>{t('Destination StorageClass')}</strong>
65	              </Td>
66	              <Td>
67	                {destinationStorageClass}{' '}
68	                {defaultStorageClassName === destinationStorageClass ? '(default)' : ''}
69	              </Td>
70	            </Tr>
71	            <Tr>
72	              <Td width={30}>
73	                <strong>
74	                  {t('Migrating {{migrationCount}} out of {{allCount}}', {
75	                    allCount: volumes?.length,
76	                    migrationCount: volumesToMigrate?.length,
77	                  })}
78	                </strong>
79	              </Td>
80	              <Td>
81	                {volumesToMigrate.map((volume) => (
82	                  <div key={volume.name}>{volume.name}</div>
83	                ))}
84	              </Td>
85	            </Tr>
86	          </Tbody>
87	        </Table>
88	
89	        {migrationError && (
90	          <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
91	            {migrationError?.message}
92	          </Alert>
93	        )}
94	      </StackItem>
95	    </Stack>
96	  );
97	};
98	
99	export default VirtualMachineMigrationReviewTab;

